# ─── CONFIGURATION ───────────────────────────────────────────────
def _env_or(key, fallback):
    val = os.environ.get(key)
    return val if val else fallback


def _env_bool(key, fallback=False):
    val = os.environ.get(key)
    if val is None or val == "":
        return bool(fallback)
    return str(val).strip().lower() not in ("0", "false", "no", "off")


